int main() {
    string s;
    cin >> s;
    int k;
    cin >> k;

    int max_a = 0;
    int current_a = 0;

    if (s.length() < k) {
        cout << 0 << endl;
        return 0;
    }

    for (int i = 0; i < k; ++i) {
        if (s[i] == 'a') {
            current_a++;
        }
    }
    max_a = current_a;

    for (int i = k; i < s.length(); ++i) {
        if (s[i] == 'a') {
            current_a++;
        }
        if (s[i - k] == 'a') {
            current_a--;
        }
        max_a = max(max_a, current_a);
    }

    cout << max_a << endl;

    return 0;
}

