#include <stdio.h>
#include <string.h>

int main() {
    char s[1000001];
    int k;
    scanf("%s", s);
    scanf("%d", &k);

    int max_a = 0, current_a = 0;
    int n = strlen(s);

    if (n < k) {
        printf("0\n");
        return 0;
    }

    for (int i = 0; i < k; i++) {
        if (s[i] == 'a') {
            current_a++;
        }
    }
    max_a = current_a;

    for (int i = k; i < n; i++) {
        if (s[i] == 'a') {
            current_a++;
        }
        if (s[i - k] == 'a') {
            current_a--;
        }
        if (current_a > max_a) {
            max_a = current_a;
        }
    }
    printf("%d\n", max_a);
    return 0;
}

