import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main (String[] args) throws java.lang.Exception {
        Scanner sc = new Scanner(System.in);
        String s = sc.next();
        int k = sc.nextInt();

        int max_a = 0, current_a = 0;

        if (s.length() < k) {
            System.out.println(0);
            return;
        }

        for (int i = 0; i < k; i++) {
            if (s.charAt(i) == 'a') {
                current_a++;
            }
        }
        max_a = current_a;

        for (int i = k; i < s.length(); i++) {
            if (s.charAt(i) == 'a') {
                current_a++;
            }
            if (s.charAt(i - k) == 'a') {
                current_a--;
            }
            max_a = Math.max(max_a, current_a);
        }
        System.out.println(max_a);
    }
}

